UPDATE archivio_items SET abstract = 'Nella pubblicità girata da Libera viene ripreso un omicidio di Camorra. La polizia allontana i curiosi dalla scena del delitto, di cui rimane un contorno del cadavere fatto con il gesso. Una bambina riesce a eludere la sorveglianza, si avvicina al contorno di gesso, prova a cancellarlo con la mano ma non ci riesce. Viene poi inquadrata una lavagna con su scritto "la Camorra", la bambina si avvicina e cancella la scritta con la mano. Una scritta in sovraimpressione recita: aiutialmola a cancellare questa vergogna".' WHERE id_originale = 32251;
UPDATE archivio_items SET abstract = 'Nella pubblicità realizzata da Libera si vedono alcuni bambini che disegnano sull''asfalto con dei gessetti. Passano in sovraimpressione delle scritte che ci dicono che la casa è stata confiscata alla mafia. Messaggio: "e tu da che parte stai?"' WHERE id_originale = 32253;
UPDATE archivio_items SET abstract = 'In questo spot, realizzato da Libera, alcuni bambini si coprono la faccia per non vedere le immagini di un uomo morto, un ragazzo che si buca, una nave stracarica di immigrati proveniente da Tirana ecc. Lo spot mostra poi le facce dei bambini sorridenti e passa dal bianco e nero ai colori. Messaggio: "l''indifferenza è una malattia mortale"' WHERE id_originale = 32254;
UPDATE archivio_items SET abstract = 'Lo spot è stato girato da Libera. Vengono mostrate immagini di un capannone in cui la Mafia per anni ha compiuto crimini. Lo spot termina mostrando un gruppo di bambini che vi entra per giocarci. Messaggio: "da luogo di morte a luogo di vita senza dimenticare".' WHERE id_originale = 32255;
