UPDATE archivio_items SET abstract = 'Spot realizzato da United Nations Office on Drugs and Crime che tratta il tema dello sfruttamento sessuale. Nello spot si vedono in sovraimpressione delle scritte che sono le promesse fatte alle donne per venire nei paesi ricchi. Quindi, lavoro, opportunità, soldi, felicità. Nella realtà, come ci è mostrato dalle immagini, si tratta di prostituzione, droga, violenza e sfruttamento sessuale. "Più di 700.000 donne subiscono la tratta ogni anno con lo scopo dello sfruttamento sessuale e del lavoro forzato".' WHERE id_originale = 32353;
